using System.Text.Json;
using Confluent.Kafka;
using CourtParser.Common.Kafka.Abstraction;
using CourtParser.Common.Kafka.KafkaHelpers;
using CourtParser.Common.Kafka.Messages;
using CourtParser.Common.Options;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Options;

namespace CourtParser.Infrastructure.Producers;

public class KafkaCourtMessageProducer : IKafkaProducer
{
    private readonly IProducer<Null, string> _producer;
    private readonly KafkaOptions _config;
    private readonly ILogger<KafkaCourtMessageProducer> _logger;
    private readonly KafkaTopicHelpers _topicHelpers;
    private readonly HashSet<string> _verifiedTopics = [];

    public KafkaCourtMessageProducer(
        IOptions<KafkaOptions> config, 
        ILogger<KafkaCourtMessageProducer> logger,
        KafkaTopicHelpers topicHelpers)
    {
        _config = config.Value;
        _logger = logger;
        _topicHelpers = topicHelpers;

        var producerConfig = new ProducerConfig
        {
            BootstrapServers = _config.BootstrapServers,
            ClientId = _config.ClientId,
            MessageSendMaxRetries = _config.MessageSendMaxRetries,
            RetryBackoffMs = _config.RetryBackoffMs,
        };

        _producer = new ProducerBuilder<Null, string>(producerConfig)
            .SetErrorHandler(OnProducerError)
            .Build();
    }

    public async Task ProduceAsync(string topic, CourtCaseMessage message)
    {
        await EnsureTopicExistsAsync(topic);
        
        try
        {
            var jsonMessage = JsonSerializer.Serialize(message, new JsonSerializerOptions
            {
                PropertyNamingPolicy = JsonNamingPolicy.CamelCase
            });

            var kafkaMessage = new Message<Null, string> 
            { 
                Value = jsonMessage,
                Timestamp = new Timestamp(DateTime.UtcNow)
            };

            var result = await _producer.ProduceAsync(topic, kafkaMessage);
            
            _logger.LogDebug("Сообщение отправлено в топик {Topic}, partition {Partition}, offset {Offset}",
                result.Topic, result.Partition.Value, result.Offset.Value);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Ошибка отправки сообщения в топик {Topic}", topic);
            throw;
        }
    }

    public async Task ProduceBatchAsync(string topic, List<CourtCaseMessage> messages)
    {
        await EnsureTopicExistsAsync(topic);
        
        var sendTasks = messages.Select(message => ProduceAsync(topic, message));
        
        try
        {
            await Task.WhenAll(sendTasks);
            _logger.LogInformation("Успешно отправлено {Count} сообщений в топик {Topic}", 
                messages.Count, topic);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Ошибки при отправке batch в топик {Topic}", topic);
            throw;
        }
    }

    public async Task ProduceBatchWithRetryAsync(string topic, List<CourtCaseMessage> messages, int maxRetries = 3)
    {
        for (int attempt = 1; attempt <= maxRetries; attempt++)
        {
            try
            {
                await ProduceBatchAsync(topic, messages);
                return;
            }
            catch (Exception ex) when (attempt < maxRetries)
            {
                _logger.LogWarning(ex, "Попытка {Attempt}/{MaxRetries} не удалась. Повтор через 2 секунды...", 
                    attempt, maxRetries);
                await Task.Delay(2000);
            }
        }
        
        throw new Exception($"Не удалось отправить batch после {maxRetries} попыток");
    }

    private async Task EnsureTopicExistsAsync(string topic, bool forceCheck = false)
    {
        if (_verifiedTopics.Contains(topic) && !forceCheck)
            return;

        await _topicHelpers.EnsureTopicExistsAsync(
            _config.BootstrapServers, 
            topic,
            numPartitions: 3,
            replicationFactor: 1);
        
        _verifiedTopics.Add(topic);
    }

    private void OnProducerError(IProducer<Null, string> producer, Error error)
    {
        _logger.LogError("Kafka producer error: {Reason} (Code: {Code})", error.Reason, error.Code);
    }
    
    public async Task ProduceSingleMockMessageAsync(string topic)
    {
        var random = new Random();
        
        var mockMessage = new CourtCaseMessage
        {
            Title = "Тестовое дело - ТЕСТ-001/2024",
            Link = "https://example.com/test/1",
            CaseNumber = $"ТЕСТ-{random.Next(1,9999)}",
            CourtType = "Тестовый суд",
            OriginalCaseLink = "https://test.sudrf.ru/test/1",
            HasDecision = true,
            DecisionLink = "https://example.com/test/decision/1",
            DecisionType = "Тестовое решение",
            FederalDistrict = "Тестовый федеральный округ",
            Region = "Тестовый регион",
            Plaintiff = "Тестовый истец",
            Defendant = "Тестовый ответчик",
            ThirdParties = "Тестовые третьи лица",
            Representatives = "ТЕстовые представители",
            CaseResult = "Типо результат",
            ReceivedDate = DateTime.UtcNow.AddDays(-1),
            CaseCategory = "Тестовая категория",
            CaseSubcategory = "Тестовая подкатегория",
            DecisionContent = "Решение\nк делу №2-2091/2019\n\nУИД 23RS0051-01-2019-002691-48\n\nРЕШЕНИЕ\n\nИменем Российской Федерации\n\nг.Тимашевск                             04 декабря 2019 года\n\nТимашевский районный суд Краснодарского края в составе\n\nпредседательствующего                     Жане Х.А.,\n\nпри секретаре                                              Головко А.А.,\n\nс участием истца                     <ФИО>1,\n\nрассмотрев в открытом судебном заседании гражданское дело по исковому заявлению <ФИО>1 к администрации Роговского сельского поселения <адрес> о включении имущества в наследственную массу и признании права собственности,\n\nустановил:\n\n<ФИО>1 обратилась в суд с исковым заявлением к администрации Роговского сельского поселения <адрес> о включении имущества в наследственную массу и признании права собственности.\n\nВ обоснование требований указала, что <дд.мм.гггг> умер, дедушка истца <ФИО>5\n\nИстец приняла наследство по завещанию на земельный участок площадью 1700 кв.м. с кадастровым номером <№>, земли населенных пунктов для личного подсобного хозяйства, расположенный по адресу: <адрес>, что подтверждается свидетельством о праве на наследство по завещанию серии <адрес>9 от <дд.мм.гггг>, выданным нотариусом Тимашевского нотариального <адрес>, зарегистрированные в реестре за <№>\n\nВ ходе оформления наследственных прав выяснилось, что на земельном участке, располагается жилой дом, однако правоустанавливающие документы у наследодателя на жилой дом – отсутствовали, что в настоящее время препятствует истцу в надлежащем оформлении своих наследственных прав, без вынесения решения суда.\n\nВ судебном заседании истец, заявленные требования поддержала, просила суд включить в наследственную массу, открывшеюся после смерти наследодателя. <ФИО>2, умершего <дд.мм.гггг>, жилой дом обшей площадью <№> кв.м., этажность <№> года постройки, материал стен - кирпичные, расположенный по адресу: <адрес> признать право собственности в порядке наследования за <ФИО>1 на указанную недвижимость.\n\nПредставитель ответчика, будучи надлежащим образом извещенный, о дате и месте судебного заседания, в судебные заседания, назначенные на <дд.мм.гггг>, <дд.мм.гггг>, не явился, документов уважительности неявки не предоставил.\n\nСогласно почтовым уведомлениям представитель ответчика администрации Роговского сельского поселения <адрес> извещен о дне судебного заседания, назначенного на <дд.мм.гггг> – <дд.мм.гггг>, а назначенного на <дд.мм.гггг> -<дд.мм.гггг>.\n\nТретье лицо - нотариус Тимашевского нотариального округа, будучи надлежащим образом, уведомленным о времени и месте слушания дела, в судебное заседание не явился, с исковым заявлением ознакомлен, представил заявление о рассмотрении заявленных требований в свое отсутствие, против их удовлетворения не возражал.\n\nВ связи с чем, с учетом мнения истца, которая против вынесения решения в отсутствие представителя ответчика не возражала, суд считает возможным рассмотреть дело в его отсутствие, по имеющимся в деле материалам.\n\nВыслушав истца, исследовав представленные доказательства, суд считает, что исковые требования подлежат удовлетворению по следующим основаниям.\n\nТак, <дд.мм.гггг> умер, дедушка истца <ФИО>5\n\nИстец приняла наследство по завещанию на земельный участок площадью <№> кв.м. с кадастровым номером <№>, земли населенных пунктов для личного подсобного хозяйства, расположенный по адресу: <адрес>, что подтверждается свидетельством о праве на наследство по завещанию серии <адрес>9 от <дд.мм.гггг>, выданным нотариусом Тимашевского нотариального <адрес>, зарегистрированные в реестре за <№>\n\nПраво собственности на земельный участок зарегистрировано, что подтверждается выпиской из единого государственного реестра недвижимости об основных характеристиках и зарегистрированных правах на объект недвижимости от <дд.мм.гггг>, о чем свидетельствует запись регистрации <№> от <дд.мм.гггг>.\n\nСогласно справке отдела по <адрес> Государственного бюджетного учреждения <адрес> «Краевая техническая инвентаризация - Краевой БТИ» от <дд.мм.гггг> <№>, право собственности на жилой дом, расположенный по адресу: <адрес>. за <ФИО>2, умершим <дд.мм.гггг>, не зарегистрировано и правоустанавливающие документы на имущество отсутствуют.\n\nСогласно выписке из ЕГРН об основных характеристиках и зарегистрированных правах на объект недвижимости <№> от <дд.мм.гггг>, сведения о зарегистрированных правах на жилой дом расположенный по адресу: <адрес>, так же отсутствуют.\n\nИсходя из данных представленных нотариусом Тимашевского нотариального округа, после смерти <ФИО>2, наследниками последнего по завещанию, в соответствии со ст.1152 ГК РФ, явились внучка наследодателя – <ФИО>1, которой в установленный законом срок подано соответствующее заявление о принятии наследства умершего.\n\nВ выдаче свидетельства о праве на наследство по закону, на спорную часть наследственного имущества - отказано, поскольку право собственности умершего на указанный объект недвижимости не подтверждено.\n\nВместе с тем, как установлено в судебном заседании, за умершим право на спорное имущество, из владения последнего не выбывало и фактически никому не передавалось.\n\nУчитывая обстоятельства дела в их совокупности, оценивая представленные сторонами доказательства в силу требований ст.67 ГПК РФ, суд приходит к выводу о необходимости удовлетворения заявленных требований.\n\nНа основании изложенного, руководствуясь ст.ст.194-198 ГПК РФ, суд\n\nрешил:\n\nИсковое заявление <ФИО>1 к администрации Роговского сельского поселения <адрес> о включении имущества в наследственную массу и признании права собственности – удовлетворить.\n\nВключить в наследственную массу, открывшеюся после смерти наследодателя, <ФИО>2, умершего <дд.мм.гггг>, жилой дом обшей площадью <№> кв.м., этажность <№> года постройки, материал стен - кирпичные, расположенный по адресу: <адрес>.\n\nПризнать право собственности в порядке наследования за <ФИО>1 на жилой дом общей площадью <№> кв.м., этажность <№> года постройки, материал стен - кирпичные, расположенный по адресу: <адрес> после смерти наследодателя, <ФИО>2, умершего <дд.мм.гггг>.\n\nРешение является основанием для регистрации права собственности в Управлении Федеральной службы государственной регистрации, кадастра и картографии по <адрес>.\n\nРешение может быть обжаловано в апелляционном порядке в Краснодарский краевой суд через Тимашевский районный суд в течение месяца со дня его мотивированного составления.\n\nМотивированное решение суда составлено 09.12.2019.\n\nСудья Жане Х.А.\"\"\"\n\nCASE_2 = \"\"\"К делу №2-2058/2019\n\nУИД <№>\n\nР Е Ш Е Н И Е\n\nИменем Российской Федерации\n\nг. Тимашевск                                                                                18 ноября 2019 года\n\nТимашевский районный суд Краснодарского края в составе:\n\nпредседательствующего судьи        Балашовой Л.А.,\n\nпри секретаре судебного заседания        Войщевой Н.Н.,\n\nрассмотрев в открытом судебном заседании гражданское дело по исковому заявлению Ситниковой Татьяны Николаевны к администрации муниципального об-разования Тимашевского района об установлении факта принятия наследства при-знании права собственности,\n\nустановил:\n\nСитникова Т.Н. обратилась в суд с исковым заявлением об установления факта принятия наследства, оставшегося после смерти матери <ФИО>16-шей <дд.мм.гггг>, в виде земельного участка, категории земель: земли насе-ленных пунктов, для обслуживания жилого дома с кадастровым номером <№> общей площадью 522 кв.м. и расположенный на нем жилой дом общей площадью 11.6 кв.м., кадастровый <№> находящиеся по адресу: <адрес> и признании право собственности, указав, что <дд.мм.гггг> умерла ее мать <ФИО>1. После смерти наследодателя осталось вышеуказанное имущество. <дд.мм.гггг> определением Тимашевского районного суда за Ситниковой Татьяной Николаевной и дочерью Расламбековой Янной Эдуардовной признано право собственности по 1/3 доле за каждой, выше указанного домовладе-ния. Поскольку Ситниковой Т.Н. пропущен установленный законом срок для при-нятия наследства. После смерти <ФИО>1 истец похоронила ее за счет своих денежных средств, пользуется земельным участком, несет бремя содержания жило-го дома. В ином порядке она не может восстановить свои наследственные права, поэтому вынуждена обратиться в суд.\n\nИстец Ситникова Т.Н. в судебное заседание не явилась, надлежаще образом уведомленная о времени и месте слушания по делу, направив суду заявление, в ко-тором просила рассмотреть дело в ее отсутствие, настаивала на удовлетворении ис-ковых требований.\n\nПредставитель ответчика - администрации муниципального образования Ти-машевского района <ФИО>6 О.А. в судебное заседание не явился, надлежаще об-разом уведомленный о времени и месте слушания по делу, направив суду дополне-ния к возражениям, в котором просил рассмотреть дело в его отсутствие, по приня-тию решения полагался на усмотрения суда.\n\nПривлеченное третье лицо Расламбекова Я.Э. в судебное заседание не яви-лась, надлежаще образом уведомленная о времени и месте слушания по делу, направила суду заявление, в котором не возражала против удовлетворения исковых требований, также указав, что отказывается от причитающейся ей доли наследства в имуществе <ФИО>1, умершей <дд.мм.гггг>. Просила рассмотреть дело в ее отсутствие.\n\nТретье лицо –нотариус Тимашевского нотариального округа Краснодарского края <ФИО>9 в судебное заседание не явилась, направила суду справку, в ко-тором просила рассмотреть дело в ее отсутствие, указав, что после смерти <ФИО>17 <ФИО>1, умершей <дд.мм.гггг> заведено наследственное дело. Заявление о принятии наследства по закону было подано дочерью наследодателя Ситниковой Татьяной Николаевной, однако ей было отказано, в связи с тем, что она пропустила установленный законом срок для принятия наследства.\n\nНеявка лица, извещенного в установленном порядке о времени и месте рас-смотрения дела, является его волеизъявлением, свидетельствующим об отказе от реализации своего права на непосредственное участие в судебном разбирательстве дела и иных процессуальных прав, поэтому не может быть препятствием для рас-смотрения судом дела по существу.\n\nСуд приходит к выводу о возможности рассмотреть дело в отсутствие сторон в соответствии со ст.167 ГПК РФ.\n\nИсследовав материалы дела, суд считает требования искового заявления обоснованными и подлежащими удовлетворению по следующим основаниям.\n\nВ соответствии со ст.55 ГПК РФ, доказательствами по делу являются полу-ченные в предусмотренном законом порядке сведения о фактах, на основе которых суд устанавливает наличие или отсутствие обстоятельств, обосновывающих требо-вания и возражения сторон, а также иных обстоятельств, имеющих значение для правильного рассмотрения и разрешения дела. Эти сведения могут быть получены из объяснений сторон и третьих лиц, показаний свидетелей, письменных и веще-ственных доказательств, аудио и видеозаписей, заключений эксперта.\n\nСт. 56 ГПК ГК РФ предусматривает, что каждая сторона должна доказать те обстоятельства, на которые она ссылается как на основания своих требования и возражений, при этом в соответствии со ст.60 ГПК РФ «Обстоятельства дела, кото-рые в соответствии с законом должны быть подтверждены определенными сред-ствами доказывания, не могут подтверждаться никакими другими доказательства-ми».\n\nНа основании ч.3 ст.67 ГПК ПРФ суд оценивает относимость, допустимость, достоверность каждого доказательства в отдельности, а также достаточность и вза-имную связь доказательств в их совокупности.\n\nИз материалов деле следует, что <дд.мм.гггг> умерла мать истицы – <ФИО>1, что подтверждается свидетельством о смерти серии II-AГ <№> от <дд.мм.гггг>, выданным Отделом ЗАГС Управлением ЗАГС Краснодарского края отдел ЗАГС, о чем <дд.мм.гггг> составлена запись акта о смерти <№>.\n\nРодственные отношения Ситниковой (Цывенко) Татьяны Николаевны, с наследодателем подтверждаются свидетельством о рождении <№>, согласно переводу нотариуса нотариального округа <адрес> <ФИО>10, в графе мать указана <ФИО>1.\n\nСвидетельством о заключении брака, подтверждается то, что истец сменила фамилию с Цывенко на Ситникову.\n\nИз материалов дела установлено, что после смерти наследодателя осталось имущество в виде земельного участка, категории земель: земли населенных пунк-тов, для обслуживания жилого дома с кадастровым номером <№> об-щей площадью 522 кв.м. и расположенный на нем жилой дом общей площадью 11.6 кв.м., кадастровый <№> находящиеся по адресу: Красно-дарский край <адрес>.\n\nИз отзыв на исковое заявление нотариуса <ФИО>9, следует, что после смерти <ФИО>1, умершей <дд.мм.гггг>, заведено наследственное дело. Заявление о принятии наследства по закону было подано до-черью наследодателя Ситниковой Татьяной Николаевной, однако ей было отказано, в связи с тем, что она пропустила установленный законом срок для принятия наследства.\n\n<дд.мм.гггг> определением Тимашевского районного суда за Ситнико-вой Татьяной Николаевной и дочерью Расламбековой Янной Эдуардовной призна-но право собственности по 1/3 доле за каждой, выше указанного домовладения.\n\nВместе с тем, после смерти наследодателя <ФИО>1, истец, похоронила мать за счет своих денежных средств, заявление о принятии наследства после смер-ти матери не стала подавать, при этом пользовалась земельным участком, поддер-живала жилой дом в надлежащем состоянии, распрягалась и пользовалась наслед-ственным имуществом, поддерживая его в надлежащем состоянии.\n\nСогласно справки <№> об уточнении адреса, выданной МУ «Управление ар-хитектуры и градостроительства муниципального образования <адрес>», материалам учетно-справочного характера, адресному пла-ну <адрес> домовладение принадлежит по 1/3 доли <ФИО>3-евне – Ситниковой Татьяне Николаевне и Ситниковой Янне Эдуардовне и имеет почтовый адресу: <адрес>.\n\nВ соответствии с пунктом 2 ст.8 ГК РФ права на имущество, подлежащее государственной регистрации, возникают с момента регистрации соответствующих прав на него, если иное не установлено законом.\n\nПолучение свидетельства о праве на наследство является правом, а не обя-занностью наследника, поэтому отсутствие такого свидетельства не может служить основанием для отказа в принятии искового заявления по спору о наследстве (ста-тья 134 ГПК РФ), возвращения такого искового заявления (статья 135 ГПК РФ) или оставления его без движения (статья 136 ГПК РФ).\n\nПри отсутствии надлежаще оформленных документов, подтверждающих право собственности наследодателя на имущество, судами до истечения срока при-нятия наследства (статья 1154 ГК РФ) рассматриваются требования наследников о включении этого имущества в состав наследства, а если в указанный срок решение не было вынесено, также требования о признании права собственности в порядке наследования.\n\nНаследник, принявший наследство, независимо от времени и способа его принятия считается собственником наследственного имущества, носителем имуще-ственных прав и обязанностей со дня открытия наследства вне зависимости от фак-та государственной регистрации прав на наследственное имущество и ее момента (если такая регистрация предусмотрена законом).\n\nВместе с тем, у суда не вызывает сомнения принадлежность указанного иму-щества, умершей <ФИО>1, поскольку подтверждается представленными суду документами.\n\nСогласно свидетельство о праве, выданного на основании постановления гла-вы администрации <адрес> от <дд.мм.гггг> <№> на момент смерти <ФИО>1 принадлежал земельный участок для индивидуального жилищного строительства, общей площадью 522 кв.м. с кадастровым номером <№> с расположенным на нем домовладением общей площадью 11.6 кв.м с кадастровым номером <№> по адресу: <адрес>.\n\nВ соответствии с ч.1 ст.1142 ГК РФ наследниками первой очереди по закону являются дети, супруг и родители наследодателя.\n\nВ соответствии с п. 2 ч. 2 ст. 218 ГК РФ, в случае смерти гражданина право собственности на принадлежавшее ему имущество переходит по наследству к дру-гим лицам в соответствии с завещанием или законом.\n\nВместе с тем, из материалов дела следует, а также не оспаривалось сторона-ми, Расламбекова Я.Э. от вышеуказанного наследственного имущества отказывает-ся в пользу Ситниковой Т.Н.\n\nСогласно ч.1 ст.1152 ГК РФ для приобретения наследства наследник должен его принять.\n\nВ соответствии с ч.1 ст.1153 ГПК РФ принятие наследства осуществляется подачей по месту открытия наследства нотариусу или уполномоченному в соответ-ствии с законом выдавать свидетельства о праве на наследство должностному лицу заявления наследника о принятии наследства либо заявления наследника о выдаче свидетельства о праве на наследство.\n\nВ силу ст. 1154 Гражданского кодекса Российской Федерации наследство может быть принято в течение шести месяцев со дня открытия наследства.\n\nСогласно разъяснениям п. 36 постановления Пленума Верховного Суда РФ от 29.05.2012 года N 9 \"О судебной практике по делам о наследовании\", под соверше-нием наследником действий, свидетельствующих о фактическом принятии наслед-ства, следует понимать совершение предусмотренных пунктом 2 статьи 1153 Граж-данского кодекса Российской Федерации действий, а также иных действий по управлению, распоряжению и пользованию наследственным имуществом, поддер-жанию его в надлежащем состоянии распоряжению и пользованию наследственным имуществом, поддержанию его в надлежащем состоянии, в которых проявляется отношение наследника к наследству как к собственному имуществу.\n\nС учетом исследованных в ходе рассмотрения гражданского дела доказа-тельств, суд полагает установленным, что истица приняла наследство в установлен-ном порядке\n\nПринимая во внимания установленные по делу обстоятельства, отсутствие возражение администрации Тимашевского городского поселения, Расламбековой Я.Э., суд считает возможным исковое заявление Ситниковой Татьяны Николаевны к администрации муниципального образования Тимашевского района об установ-лении факта принятия наследства признании права собственности удовлетворить в полном объеме.\n\nНа основании изложенного и руководствуясь ст. ст. 194-199 ГПК РФ, суд\n\nрешил:\n\n         исковые требования Ситниковой Татьяны Николаевны к администрации му-ниципального образования Тимашевского района об установлении факта принятия наследства признании права собственности – удовлетворить.\n\nУстановить факт принятия наследства Ситниковой Татьяной Николаевной по-сле смерти наследодателя <ФИО>1, умершей <дд.мм.гггг> го-да.\n\nВключить в наследственную массу и признать право собственности за Ситни-ковой Татьяной Николаевной на земельный участок, категория земель: земли насе-ленных пунктов разрешенное использование для обслуживания жилого дома с ка-дастровым номером <№> по адресу: <адрес> <адрес>, <адрес>.\n\nВключить в наследственную массу и признать право собственности за Ситни-ковой Татьяной Николаевной на 1/3 доли домовладения, общей площадью <№> кв.м., кадастровый <№> расположенного по адресу: Красно-дарский край <адрес>.\n\nРешение суда, вступившее в законную силу, является основанием для госу-дарственной регистрации наличия, возникновения, прекращения, перехода, ограни-чения (обременения) прав на недвижимое имущество и сделок с ним, а также осно-ванием для постановки на кадастровый учет объектов недвижимости и внесения изменений в сведения Государственного кадастра недвижимости.\n\nРешение может быть обжаловано в апелляционном порядке в Краснодарский краевой суд через Тимашевский районный суд в течение одного месяца со дня его принятия в окончательной форме.\n\nПредседательствующий -",
            JudgeName = "Тестовый судья",
            Timestamp = DateTime.UtcNow,
            CaseMovements =
            [
                new()
                {
                    EventName = "Регистрация иска в суде",
                    EventResult = "Иск принят к производству",
                    Basis = $"ст. {random.Next(1,9999)} ГПК РФ",
                    EventDate = DateTime.UtcNow.AddDays(-12)
                },

                new()
                {
                    EventName = "Передача материалов судье",
                    EventResult = "Материалы переданы судье Тестову А.А.",
                    Basis = "",
                    EventDate = DateTime.UtcNow.AddDays(-random.Next(1,3))
                },
                
                new()
                {
                    EventName = "Вынесение решения",
                    EventResult = "Иск удовлетворён",
                    Basis = "Решение суда от " + DateTime.UtcNow.AddDays(-3).ToShortDateString(),
                    EventDate = DateTime.UtcNow.AddDays(-3)
                }
            ]
        };

        try
        {
            await ProduceAsync(topic, mockMessage);
            _logger.LogInformation("Успешно отправлено тестовое сообщение в топик {Topic}", topic);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Ошибка отправки тестового сообщения в топик {Topic}", topic);
            throw;
        }
    }

    public void Dispose()
    {
        _producer?.Flush(TimeSpan.FromSeconds(5));
        _producer?.Dispose();
    }
